bool write_data_with_check(std::vector<uint8_t>& buffer, uint32_t header, const std::vector<uint32_t>& items) {
    // Create buffer adaptor and binary stream
    auto adaptor = hexi::buffer_adaptor(buffer);
    auto stream = hexi::binary_stream(adaptor);

    // Calculate required space: header (4 bytes) + item count (4 bytes) + items (4 bytes each)
    size_t required_space = sizeof(uint32_t) + sizeof(uint32_t) + (items.size() * sizeof(uint32_t));

