    auto write_ptr = adaptor.get_write_pointer();

    // Write header
    stream.write(header);

    // Write container data (items vector)
    stream.write_container(items);

    // Update the buffer size to reflect the written data
    buffer.resize(buffer.size() + required_space);

    return true;
}
