#include <cstdint>
#include <iostream>

// Note: push() and pop() are private, but we can observe their behavior
// through allocate() and deallocate() operations
template<size_t element_count = 10>
void demonstrate_block_allocator_behavior() {
    // Create block_allocator for uint32_t elements
    hexi::allocators::block_allocator<uint32_t> allocator;

    // Array to store pointers for later deallocation
    uint32_t* pointers[element_count];

    // Demonstrate allocation - this internally uses pop() from free list
    std::cout << "Allocating " << element_count << " blocks...\n";
    for (size_t i = 0; i < element_count; ++i) {
        pointers[i] = static_cast<uint32_t*>(allocator.allocate(1));
        if (pointers[i]) {
            *pointers[i] = static_cast<uint32_t>(i); // Initialize with index value
            std::cout << "Allocated block " << i << " at address: " << pointers[i] 
                      << " with value: " << *pointers[i] << "\n";
        } else {
            std::cout << "Failed to allocate block " << i << "\n";
        }
    }

    // Demonstrate deallocation - this internally uses push() to free list
    std::cout << "\nDeallocating every other block...\n";
    for (size_t i = 0; i < element_count; i += 2) {
        std::cout << "Deallocating block " << i << " at address: " << pointers[i] << "\n";
        allocator.deallocate(pointers[i], 1);
        pointers[i] = nullptr; // Mark as deallocated
    }

    // Allocate some more blocks - these should come from the free list (recently deallocated)
    std::cout << "\nAllocating 3 more blocks (should reuse deallocated ones)...\n";
    for (size_t i = 0; i < 3; ++i) {
        uint32_t* new_ptr = static_cast<uint32_t*>(allocator.allocate(1));
        if (new_ptr) {
            *new_ptr = static_cast<uint32_t>(100 + i); // New value to distinguish
            std::cout << "Reallocated block at address: " << new_ptr 
                      << " with value: " << *new_ptr << "\n";
        }
    }

    // Deallocate remaining blocks
    std::cout << "\nDeallocating all remaining blocks...\n";
    for (size_t i = 0; i < element_count; ++i) {
        if (pointers[i] != nullptr) {
            std::cout << "Deallocating block at address: " << pointers[i] << "\n";
            allocator.deallocate(pointers[i], 1);
        }
    }

