    uint32_t* final_ptr = static_cast<uint32_t*>(allocator.allocate(1));
    if (final_ptr) {
        *final_ptr = 999;
        std::cout << "Final allocation at address: " << final_ptr 
                  << " with value: " << *final_ptr << "\n";
        allocator.deallocate(final_ptr, 1);
    }

    std::cout << "\nBlock allocator demonstration completed.\n";
}
