#include <cstdint>

template<size_t block_size = 1024>
std::vector<uint8_t> preview_data_without_consuming(const hexi::detail::intrusive_storage<block_size>& storage, size_t bytes_to_preview) {
    // Get the readable size to ensure we don't try to read more than available
    size_t readable_size = storage.readable_size();
    size_t actual_bytes_to_read = std::min(bytes_to_preview, readable_size);

    // Create a vector to hold the preview data
    std::vector<uint8_t> result(actual_bytes_to_read);

    // Use peek operation to read data without advancing the read pointer
    if (actual_bytes_to_read > 0) {
        storage.peek(result.data(), actual_bytes_to_read);
    }

    return result;
}

template<size_t block_size = 1024>
struct BufferStatus {
    size_t readable_size;
    size_t free_space;
};

BufferStatus<> check_buffer_status(const hexi::detail::intrusive_storage<1024>& storage) {
    BufferStatus<> status;
    status.readable_size = storage.readable_size();
    status.free_space = storage.free_size();
    return status;
}

template<size_t block_size = 1024>
void reset_buffer(hexi::detail::intrusive_storage<block_size>& storage) {
    // Reset both read and write offsets to effectively clear the buffer
    storage.reset();
}

