struct MeasurementData {
    uint32_t sensor_id;
    std::vector<float> temperatures;
    double pressure;

    void serialise(auto& adaptor) const {
        // Write sensor_id directly
        adaptor.write(sensor_id);

        // Convert each temperature to little-endian and write
        for (const auto& temp : temperatures) {
            auto le_temp = hexi::conditional_reverse(temp, std::endian::native, std::endian::little);
            adaptor.write(le_temp);
        }

        // Convert pressure to little-endian and write
        auto le_pressure = hexi::conditional_reverse(pressure, std::endian::native, std::endian::little);
        adaptor.write(le_pressure);
    }

    void serialise(auto& adaptor) {
        // Read sensor_id directly
        adaptor.read(sensor_id);

        // Read temperatures and convert from little-endian to native
        for (auto& temp : temperatures) {
            adaptor.read(temp);
            hexi::little_to_native_inplace(temp);
        }

        // Read pressure and convert from little-endian to native
        adaptor.read(pressure);
        hexi::little_to_native_inplace(pressure);
    }
};

